const html = $input.first().json.data;

// Remove scripts and style blocks
let clean = html.replace(/<script[\s\S]*?<\/script>/gi, '');
clean = clean.replace(/<style[\s\S]*?<\/style>/gi, '');

// Remove all remaining HTML tags
clean = clean.replace(/<[^>]+>/g, ' ');

// Decode common HTML entities
clean = clean.replace(/&amp;/g, '&');
clean = clean.replace(/&lt;/g, '<');
clean = clean.replace(/&gt;/g, '>');
clean = clean.replace(/&nbsp;/g, ' ');
clean = clean.replace(/&#39;/g, "'");
clean = clean.replace(/&quot;/g, '"');

// Collapse whitespace
clean = clean.replace(/\s+/g, ' ').trim();

// Limit to first 3000 characters (enough for AI context)
clean = clean.substring(0, 3000);

return [{ json: { job_description_clean: clean } }];

const coverLetter = $input.first().json.cover_letter;

const formatted = coverLetter
  .split('\\n')
  .join('\n')
  .trim();

return [{ json: { cover_letter_formatted: formatted } }];

